use std::collections::HashMap;

struct StrCache {
    store: HashMap<String, String>,
}

impl StrCache {
    fn get_or_insert(&mut self, key: &str) -> &str {
        self.store.entry(key.to_owned()).or_insert_with(|| key.to_uppercase())
    }
}

fn main() {
    let mut cache = StrCache { store: HashMap::new() };
    // Use each value before the next mutable borrow
    let v1 = cache.get_or_insert("hello").to_owned();
    let v2 = cache.get_or_insert("world").to_owned();
    println!("{} {}", v1, v2);
}
